import java.util.*;
public class StreamToList {
    public static void main(String[] args) {
        int[] arr = {5, 3, 8, 1, 9, 2, 7};
        List<Integer> top3 = Arrays.stream(arr)
            .boxed()
            .sorted(Comparator.reverseOrder())
            .limit(3)
            .toList();
        System.out.println(top3);
        System.out.println(top3.get(0));
    }
}
